/// Represents the result generated by the backend/AI service.
///
/// This model will be used to hold the response from:
/// - Firebase Cloud Functions (future)
/// - OpenAI API (future)
/// - Any other AI/summarization service
class GeneratedResult {
  /// The main summary text (if requested)
  final String? summary;

  /// Questions and answers (if requested)
  final List<QuestionAnswer>? questionsAndAnswers;

  /// The type of output that was generated
  final GeneratedResultType resultType;

  /// Timestamp when the result was generated
  final DateTime generatedAt;

  /// Whether the generation was successful
  final bool success;

  /// Error message if generation failed
  final String? errorMessage;

  const GeneratedResult({
    this.summary,
    this.questionsAndAnswers,
    required this.resultType,
    required this.generatedAt,
    this.success = true,
    this.errorMessage,
  });

  /// Creates a successful result with summary only
  factory GeneratedResult.summaryOnly({
    required String summary,
  }) {
    return GeneratedResult(
      summary: summary,
      resultType: GeneratedResultType.summaryOnly,
      generatedAt: DateTime.now(),
    );
  }

  /// Creates a successful result with Q&A only
  factory GeneratedResult.questionsOnly({
    required List<QuestionAnswer> questionsAndAnswers,
  }) {
    return GeneratedResult(
      questionsAndAnswers: questionsAndAnswers,
      resultType: GeneratedResultType.questionsOnly,
      generatedAt: DateTime.now(),
    );
  }

  /// Creates a successful result with both summary and Q&A
  factory GeneratedResult.summaryAndQuestions({
    required String summary,
    required List<QuestionAnswer> questionsAndAnswers,
  }) {
    return GeneratedResult(
      summary: summary,
      questionsAndAnswers: questionsAndAnswers,
      resultType: GeneratedResultType.summaryAndQuestions,
      generatedAt: DateTime.now(),
    );
  }

  /// Creates an error result
  factory GeneratedResult.error(String message) {
    return GeneratedResult(
      resultType: GeneratedResultType.summaryOnly,
      generatedAt: DateTime.now(),
      success: false,
      errorMessage: message,
    );
  }

  bool get hasSummary => summary != null && summary!.isNotEmpty;
  bool get hasQuestions => questionsAndAnswers != null && questionsAndAnswers!.isNotEmpty;
}

/// Represents a single question and answer pair
class QuestionAnswer {
  final String question;
  final String answer;

  const QuestionAnswer({
    required this.question,
    required this.answer,
  });
}

/// The type of result that was generated
enum GeneratedResultType {
  summaryOnly,
  questionsOnly,
  summaryAndQuestions,
}
